INSERT INTO public.questions (id, exam_id, paper_id, subject_id, chapter_id, question_type, question_text, options, correct_answer, correct_answer_json, auto_gradable, source, is_active, version, source_meta, explanation)
VALUES
  ('diplomatic-20fe77d5-moex-00044', 'diplomatic-20fe77d5', 'diplomatic-20fe77d5-moex-114-7f4830a9', 'sub-diplomatic-20fe77d5-03', NULL, 'single_choice', '下列敘述何者不屬於國際關係現實主義學派對新自由制度論（Neo-liberalInstitutionalism）的典型 批評？', '["國際制度不具獨立作用，它們只是反映強權與利益分配的結果", "在無政府狀態下，即便國際制度有監督與互惠機制，但是執行這些制度的力量過於薄弱，限制了國 家間的合作程度", "新自由制度論忽略「相對利益」（relativegains）問題，國家仍可能因為發現他國獲得較大利益而拒絕 合作", "新自由制度論將國際問題過度簡化為市場資訊與效率問題，忽視國際體系各種不平等的結構性壓迫"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:25:33+00:00", "source_pdf_sha1": "9acfd86bc501", "answer_pdf_sha1": "57309a558f15", "source_family": "moex-gov-tw", "moex": {"exam_code": "114140", "c": "104", "s": "0501", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "國際關係與近代外交史", "year": "114", "exam_name": "114年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 6, "answer_corrected": false, "flags": [], "civil_slug": "diplomatic", "civil_category": "外交領事人員-韓文組"}'::jsonb, NULL),
  ('diplomatic-20fe77d5-moex-00045', 'diplomatic-20fe77d5', 'diplomatic-20fe77d5-moex-114-7f4830a9', 'sub-diplomatic-20fe77d5-03', NULL, 'single_choice', '關於「全球合作暨訓練架構」（GlobalCooperationandTrainingFramework,GCTF），下列敘述何者 錯誤？', '["臺灣與美國在2015年簽署備忘錄成立「全球合作暨訓練架構」，以拓展臺灣的國際空間", "GCTF已針對公共衛生、執法合作、婦女賦權、資訊安全、人道援助及災害防救等議題舉辦國 際研習營", "除美國外，日本、澳洲與加拿大也是GCTF的正式夥伴國（FullPartners）", "GCTF的主要目的是與理念相近的民主國家共同遏制威權主義在全球的擴張"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:25:33+00:00", "source_pdf_sha1": "9acfd86bc501", "answer_pdf_sha1": "57309a558f15", "source_family": "moex-gov-tw", "moex": {"exam_code": "114140", "c": "104", "s": "0501", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "國際關係與近代外交史", "year": "114", "exam_name": "114年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 7, "answer_corrected": false, "flags": [], "civil_slug": "diplomatic", "civil_category": "外交領事人員-韓文組"}'::jsonb, NULL),
  ('diplomatic-20fe77d5-moex-00046', 'diplomatic-20fe77d5', 'diplomatic-20fe77d5-moex-114-7f4830a9', 'sub-diplomatic-20fe77d5-03', NULL, 'single_choice', '關於「銳實力」的內容，下列敘述何者錯誤？', '["銳實力利用民主社會的開放性，散播假訊息與政治宣傳", "銳實力涉及強制手段，使用武力攻擊與侵略、經濟誘因與制裁，迫使他國就範", "銳實力侵蝕對民主機制的信任、限制自由言論與扭曲公共意見", "銳實力著眼於政治菁英、媒體工作者、學者與其他意見領袖，以獲取支持"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:25:33+00:00", "source_pdf_sha1": "9acfd86bc501", "answer_pdf_sha1": "57309a558f15", "source_family": "moex-gov-tw", "moex": {"exam_code": "114140", "c": "104", "s": "0501", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "國際關係與近代外交史", "year": "114", "exam_name": "114年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 8, "answer_corrected": false, "flags": [], "civil_slug": "diplomatic", "civil_category": "外交領事人員-韓文組"}'::jsonb, NULL),
  ('diplomatic-20fe77d5-moex-00047', 'diplomatic-20fe77d5', 'diplomatic-20fe77d5-moex-114-7f4830a9', 'sub-diplomatic-20fe77d5-03', NULL, 'single_choice', '下列那個國家同時參與這三個多邊機制：AUKUS、QUAD和FiveEyes？', '["印度", "日本", "加拿大", "澳洲"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:25:33+00:00", "source_pdf_sha1": "9acfd86bc501", "answer_pdf_sha1": "57309a558f15", "source_family": "moex-gov-tw", "moex": {"exam_code": "114140", "c": "104", "s": "0501", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "國際關係與近代外交史", "year": "114", "exam_name": "114年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 9, "answer_corrected": false, "flags": [], "civil_slug": "diplomatic", "civil_category": "外交領事人員-韓文組"}'::jsonb, NULL),
  ('diplomatic-20fe77d5-moex-00048', 'diplomatic-20fe77d5', 'diplomatic-20fe77d5-moex-114-7f4830a9', 'sub-diplomatic-20fe77d5-03', NULL, 'single_choice', '日本政府在 2023 年提出為了推動「自由開放的印度太平洋」願景（Free and Open Indo-Pacific, FOIP）的新計畫，其主要內容不包含下列那個項目？', '["建立一個維護和平、確立「自由」、「透明」及「法治」原則，且弱者不會因武力壓迫而屈服的 印太環境", "擴展國際合作，提升印太各國在面對氣候變遷、公共衛生、防災及災害應變與網路安全等各種 挑戰的韌性與永續性", "建立保障印太區域集體安全的軍事協調機制，強化各國軍事體系相互協作的能力", "擴展安全範圍，從海洋延伸至空域，確保整體印太公共區域之安全與穩定"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:25:33+00:00", "source_pdf_sha1": "9acfd86bc501", "answer_pdf_sha1": "57309a558f15", "source_family": "moex-gov-tw", "moex": {"exam_code": "114140", "c": "104", "s": "0501", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "國際關係與近代外交史", "year": "114", "exam_name": "114年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 10, "answer_corrected": false, "flags": [], "civil_slug": "diplomatic", "civil_category": "外交領事人員-韓文組"}'::jsonb, NULL),
  ('diplomatic-20fe77d5-moex-00049', 'diplomatic-20fe77d5', 'diplomatic-20fe77d5-moex-114-7f4830a9', 'sub-diplomatic-20fe77d5-03', NULL, 'single_choice', '1856年克里米亞戰爭結束，列強召開巴黎和會，關於戰後的和平，下列敘述何者錯誤？', '["多瑙河航行自由化", "黑海中立化、軍艦不得隨意進出兩海峽", "同意讓土耳其成為歐洲社會的一員", "敵船上的中立國貨物得予以沒入並充公"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:25:33+00:00", "source_pdf_sha1": "9acfd86bc501", "answer_pdf_sha1": "57309a558f15", "source_family": "moex-gov-tw", "moex": {"exam_code": "114140", "c": "104", "s": "0501", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "國際關係與近代外交史", "year": "114", "exam_name": "114年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 11, "answer_corrected": false, "flags": [], "civil_slug": "diplomatic", "civil_category": "外交領事人員-韓文組"}'::jsonb, NULL),
  ('diplomatic-20fe77d5-moex-00050', 'diplomatic-20fe77d5', 'diplomatic-20fe77d5-moex-114-7f4830a9', 'sub-diplomatic-20fe77d5-03', NULL, 'single_choice', '1899年9月美國國務卿海約翰（JohnHay）對美國駐英、德、日、俄等國大使發出訓令，命各大 使向駐在國爭取支持對華門戶開放政策，那個國家回應得最冷淡？', '["俄國", "英國", "日本", "德國"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:25:33+00:00", "source_pdf_sha1": "9acfd86bc501", "answer_pdf_sha1": "57309a558f15", "source_family": "moex-gov-tw", "moex": {"exam_code": "114140", "c": "104", "s": "0501", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "國際關係與近代外交史", "year": "114", "exam_name": "114年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 12, "answer_corrected": false, "flags": [], "civil_slug": "diplomatic", "civil_category": "外交領事人員-韓文組"}'::jsonb, NULL),
  ('diplomatic-20fe77d5-moex-00051', 'diplomatic-20fe77d5', 'diplomatic-20fe77d5-moex-114-7f4830a9', 'sub-diplomatic-20fe77d5-03', NULL, 'single_choice', '關於鴉片戰爭，下列敘述何者正確？', '["英國方面重視商務問題，早在乾隆年間，便已派遣阿美士德（William Pitt Amherst, 1st Earl Amherst）前來交涉", "由於自由主義貿易理論盛行，英國在清朝道光年間，把「東印度公司」對中國貿易的特權取消， 開始准許英商自由東來貿易", "林則徐在廣州禁煙，正值英國自由黨（TheLiberalParty）執政，首相巴麥尊（HenryJohnTemple Palmerston）決定出兵", "鴉片戰爭的結果，最後在道光22年（1842年）簽訂了《中英北京條約》"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:25:33+00:00", "source_pdf_sha1": "9acfd86bc501", "answer_pdf_sha1": "57309a558f15", "source_family": "moex-gov-tw", "moex": {"exam_code": "114140", "c": "104", "s": "0501", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "國際關係與近代外交史", "year": "114", "exam_name": "114年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 13, "answer_corrected": false, "flags": [], "civil_slug": "diplomatic", "civil_category": "外交領事人員-韓文組"}'::jsonb, NULL),
  ('diplomatic-20fe77d5-moex-00052', 'diplomatic-20fe77d5', 'diplomatic-20fe77d5-moex-114-7f4830a9', 'sub-diplomatic-20fe77d5-03', NULL, 'single_choice', '關於清朝末年中法越南戰爭，下列敘述何者正確？', '["同治年間，法國殖民者已實際控制越南中南部", "清廷內部分為和、戰兩派，李鴻章積極主戰", "光緒10年（1884年），法國艦隊炮擊基隆、封鎖臺灣，當時負責臺灣軍務的是沈葆楨", "光緒11年（1885年），劉永福率領黑旗軍，於廣西鎮南關、越北諒山等地，連戰皆捷"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:25:33+00:00", "source_pdf_sha1": "9acfd86bc501", "answer_pdf_sha1": "57309a558f15", "source_family": "moex-gov-tw", "moex": {"exam_code": "114140", "c": "104", "s": "0501", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "國際關係與近代外交史", "year": "114", "exam_name": "114年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 14, "answer_corrected": false, "flags": [], "civil_slug": "diplomatic", "civil_category": "外交領事人員-韓文組"}'::jsonb, NULL),
  ('diplomatic-20fe77d5-moex-00053', 'diplomatic-20fe77d5', 'diplomatic-20fe77d5-moex-114-7f4830a9', 'sub-diplomatic-20fe77d5-03', NULL, 'single_choice', '關於義和團之亂與八國聯軍，下列敘述何者正確？', '["義和團源自白蓮教，最早流行於河南一帶", "義和團的活動，一度引起德國的抗議，清廷乃派袁世凱南來，認真督剿", "八國聯軍出兵後，共推俄國將領瓦德西（AlfredvonWaldersee）為聯軍統帥", "八國聯軍占領北京後，東南各省督撫提倡「自保」運動，以曾國藩為首領銜"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:25:33+00:00", "source_pdf_sha1": "9acfd86bc501", "answer_pdf_sha1": "57309a558f15", "source_family": "moex-gov-tw", "moex": {"exam_code": "114140", "c": "104", "s": "0501", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "國際關係與近代外交史", "year": "114", "exam_name": "114年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 15, "answer_corrected": false, "flags": [], "civil_slug": "diplomatic", "civil_category": "外交領事人員-韓文組"}'::jsonb, NULL)
